css:
.ref-wrap{max-width:920px;margin:0 auto;padding:0 16px 48px;text-align:left;color:#1a1a1a;font-size:16px;line-height:1.65}
.ref-branch{--rb-top1:#991b1b;--rb-top2:#dc2626;--rb-accent:#b91c1c;--rb-accent2:#fecaca;--rb-soft:#fff1f2;--rb-about:#fef2f2;--rb-pillbd:#e2e8f0;--rb-art-r:14px}
.ref-topbar{background:linear-gradient(105deg,var(--rb-top1),var(--rb-top2));color:#fff;text-align:center;padding:12px 16px;font-weight:700;font-size:clamp(12px,2.6vw,14px);letter-spacing:.03em;border-radius:0 0 var(--rb-art-r) var(--rb-art-r);box-shadow:0 6px 20px rgba(15,23,42,.12)}
.ref-branch-line{text-align:center;font-size:.78rem;color:#64748b;margin:14px 0 16px;font-weight:600;letter-spacing:.04em;text-transform:uppercase}
.ref-tagline{text-align:center;font-size:clamp(15px,3.5vw,20px);font-weight:800;color:#0f172a;margin:8px 0 6px}
.ref-sub{text-align:center;color:#475569;font-size:.9rem;margin:0 0 10px;max-width:36rem;margin-left:auto;margin-right:auto;line-height:1.5}
.ref-areas{display:block;text-align:center;font-size:.82rem;color:#64748b;margin:0 0 22px;font-style:italic}
.ref-quick{display:flex;flex-wrap:wrap;gap:8px;justify-content:center;margin:0 0 28px;padding:0;list-style:none}
.ref-quick li{display:inline-block}
.ref-quick a{display:inline-block;padding:8px 14px;background:#fff;border:1px solid var(--rb-pillbd);border-radius:999px;color:var(--rb-accent);font-weight:600;font-size:.82rem;text-decoration:none;transition:.15s}
.ref-quick a:hover{background:var(--rb-soft);border-color:var(--rb-accent2)}
.ref-article{background:#fff;border:1px solid #e2e8f0;border-radius:var(--rb-art-r);padding:clamp(20px,4vw,32px);box-shadow:0 8px 32px rgba(15,23,42,.07)}
.ref-h1{font-size:clamp(1.45rem,4vw,1.8rem);font-weight:900;color:var(--rb-accent);margin:0 0 16px;line-height:1.2;text-align:center;letter-spacing:-.02em}
.ref-intro{color:#334155;margin:0 0 18px;font-size:.96rem}
.ref-h2{font-size:1.12rem;font-weight:800;color:#0f172a;margin:26px 0 12px;padding-bottom:6px;border-bottom:2px solid var(--rb-accent2)}
.ref-h3{font-size:1.02rem;font-weight:700;color:var(--rb-accent);margin:18px 0 8px}
.ref-article p{color:#475569;margin:0 0 12px;font-size:.94rem;line-height:1.65}
.ref-article ul{color:#475569;margin:0 0 16px;padding-left:1.25rem;font-size:.94rem}
.ref-article li{margin-bottom:6px}
.ref-appliances{display:grid;grid-template-columns:repeat(auto-fill,minmax(138px,1fr));gap:10px;margin:16px 0}
.ref-appliances span{display:block;padding:12px 8px;text-align:center;background:var(--rb-soft);border:1px solid var(--rb-accent2);border-radius:10px;font-weight:600;font-size:.86rem;color:#334155}
.ref-about{background:var(--rb-about);border-radius:12px;padding:18px;margin:24px 0;border:1px solid var(--rb-accent2)}
.ref-about h2{margin-top:0}
.ref-copy{font-size:.72rem;color:#94a3b8;text-align:center;margin:20px 0 8px;line-height:1.5}
.ref-disclaimer{border:1px dashed var(--rb-accent2);background:color-mix(in srgb,var(--rb-soft) 65%,#fff);border-radius:10px;padding:14px 16px;font-size:.78rem;color:#57534e;margin:20px 0;line-height:1.55}
[id^=ref-]{scroll-margin-top:min(120px,18vh)}
.ref-branch--lg{--rb-top1:#7f1d1d;--rb-top2:#e11d48;--rb-accent:#be123c;--rb-accent2:#fecdd3;--rb-soft:#fff1f2;--rb-about:#fff5f5;--rb-art-r:14px}
.ref-branch--samsung{--rb-top1:#0c1929;--rb-top2:#2563eb;--rb-accent:#1e40af;--rb-accent2:#93c5fd;--rb-soft:#eff6ff;--rb-about:#f0f9ff;--rb-art-r:6px;--rb-pillbd:#bfdbfe}
.ref-branch--bosch{--rb-top1:#1e3a5f;--rb-top2:#0284c7;--rb-accent:#0369a1;--rb-accent2:#7dd3fc;--rb-soft:#f0f9ff;--rb-about:#e0f2fe;--rb-art-r:4px}
.ref-branch--siemens{--rb-top1:#0f766e;--rb-top2:#14b8a6;--rb-accent:#0d9488;--rb-accent2:#99f6e4;--rb-soft:#f0fdfa;--rb-about:#ccfbf1;--rb-art-r:16px}
.ref-branch--hitachi{--rb-top1:#7f1d1d;--rb-top2:#ea580c;--rb-accent:#c2410c;--rb-accent2:#fdba74;--rb-soft:#fff7ed;--rb-about:#ffedd5;--rb-art-r:12px}
.ref-branch--whirlpool{--rb-top1:#075985;--rb-top2:#0ea5e9;--rb-accent:#0284c7;--rb-accent2:#bae6fd;--rb-soft:#f0f9ff;--rb-about:#e0f2fe;--rb-art-r:20px}
.ref-branch--panasonic{--rb-top1:#1e1b4b;--rb-top2:#4338ca;--rb-accent:#3730a3;--rb-accent2:#c4b5fd;--rb-soft:#f5f3ff;--rb-about:#ede9fe;--rb-pillbd:#ddd6fe}
.ref-branch--toshiba{--rb-top1:#4c1d95;--rb-top2:#7c3aed;--rb-accent:#6d28d9;--rb-accent2:#d8b4fe;--rb-soft:#faf5ff;--rb-about:#f3e8ff;--rb-art-r:8px}
